+import AppKit
+import CoreGraphics
+import Foundation
+import ScreenCaptureKit
+import Vision
+
+struct ScreenTextObservation: Equatable {
+    let text: String
+    let boundingBox: CGRect
+    let confidence: Double
+}
+
+struct RecognizedScreenText: Equatable {
+    let text: String
+    let averageConfidence: Double
+
+    static func fromObservations(
+        _ observations: [ScreenTextObservation],
+        lineTolerance: CGFloat = 0.02
+    ) -> RecognizedScreenText? {
+        let nonEmptyObservations = observations.filter {
+            !$0.text.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
+        }
+        guard !nonEmptyObservations.isEmpty else {
+            return nil
+        }
+
+        let orderedObservations = nonEmptyObservations.sorted { lhs, rhs in
+            let leftMidY = lhs.boundingBox.midY
+            let rightMidY = rhs.boundingBox.midY
+            if abs(leftMidY - rightMidY) <= lineTolerance {
+                return lhs.boundingBox.midX < rhs.boundingBox.midX
+            }
+            return leftMidY > rightMidY
+        }
+
+        let text = orderedObservations
+            .map { $0.text.trimmingCharacters(in: .whitespacesAndNewlines) }
+            .joined(separator: " ")
+            .trimmingCharacters(in: .whitespacesAndNewlines)
+        guard !text.isEmpty else {
+            return nil
+        }
+
+        let totalConfidence = orderedObservations.reduce(0.0) { partialResult, observation in
+            partialResult + observation.confidence
+        }
+
+        return RecognizedScreenText(
+            text: text,
+            averageConfidence: totalConfidence / Double(orderedObservations.count)
+        )
+    }
+}
+
+struct FrontmostWindowCandidate: Equatable {
+    let windowID: CGWindowID
+    let ownerPID: pid_t
+    let layer: Int
+    let alpha: Double
+    let frame: CGRect
+}
+
+enum FrontmostWindowSelection {
+    static func selectFrontmostWindow(
+        for processID: pid_t,
+        windows: [FrontmostWindowCandidate]
+    ) -> FrontmostWindowCandidate? {
+        windows.first { window in
+            window.ownerPID == processID &&
+                window.layer == 0 &&
+                window.alpha > 0
+        }
+    }
+}
+
+protocol WindowScreenshotCapturing {
+    func captureImage() async throws -> CGImage?
+}
+
+protocol WindowTextRecognizing {
+    func recognizeText(in image: CGImage, customWords: [String]) async throws -> RecognizedScreenText?
+}
+
+protocol ScreenContextCapturing {
+    func captureContext(customWords: [String]) async -> String?
+}
+
+final class ScreenContextService: ScreenContextCapturing, @unchecked Sendable {
+    private let screenshotCapturer: any WindowScreenshotCapturing
+    private let textRecognizer: any WindowTextRecognizing
+    private let screenRecordingPermissionStateProvider: @Sendable () -> ScreenRecordingPermissionState
+    private let diagnosticLogger: @Sendable (String) -> Void
+    private let sensitiveLogger: @Sendable (String) -> Void
+
+    init(
+        screenshotCapturer: any WindowScreenshotCapturing,
+        textRecognizer: any WindowTextRecognizing,
+        screenRecordingPermissionStateProvider: @escaping @Sendable () -> ScreenRecordingPermissionState,
+        diagnosticLogger: @escaping @Sendable (String) -> Void = ScreenContextLogger.liveDiagnostic,
+        sensitiveLogger: @escaping @Sendable (String) -> Void = ScreenContextLogger.liveSensitive
+    ) {
+        self.screenshotCapturer = screenshotCapturer
+        self.textRecognizer = textRecognizer
+        self.screenRecordingPermissionStateProvider = screenRecordingPermissionStateProvider
+        self.diagnosticLogger = diagnosticLogger
+        self.sensitiveLogger = sensitiveLogger
+    }
+
+    func captureContext(customWords: [String]) async -> String? {
+        do {
+            guard let image = try await screenshotCapturer.captureImage() else {
+                diagnosticLogger("No frontmost window screenshot available.")
+                return nil
+            }
+
+            guard let recognizedText = try await textRecognizer.recognizeText(in: image, customWords: customWords) else {
+                diagnosticLogger("No frontmost window text recognized.")
+                return nil
+            }
+
+            diagnosticLogger("Captured frontmost window text for cleanup context.")
+            sensitiveLogger(recognizedText.text)
+            return recognizedText.text
+        } catch {
+            let message: String
+            if screenRecordingPermissionStateProvider() != .granted {
+                message = "Failed to capture frontmost window text because screen recording permission appears unavailable: \(error.localizedDescription)"
+            } else {
+                message = "Failed to capture frontmost window text: \(error.localizedDescription)"
+            }
+            diagnosticLogger(message)
+            return nil
+        }
+    }
+}
+
+protocol ScreenContextPrefetching: AnyObject, Sendable {
+    func start(customWords: [String])
+    func cancel()
+    func resolve() async -> ScreenContextPrefetchResult?
+}
+
+struct ScreenContextPrefetchResult: Equatable {
+    let context: String?
+    let elapsed: TimeInterval
+}
+
+final class NoOpScreenContextPrefetcher: ScreenContextPrefetching, @unchecked Sendable {
+    func start(customWords: [String]) {
+        _ = customWords
+    }
+
+    func cancel() {
+    }
+
+    func resolve() async -> ScreenContextPrefetchResult? {
+        nil
+    }
+}
+
+final class ScreenContextPrefetcher: ScreenContextPrefetching, @unchecked Sendable {
+    private let captureContext: @Sendable ([String]) async -> String?
+    private let dateProvider: @Sendable () -> Date
+    private let lock = NSLock()
+    private var task: Task<ScreenContextPrefetchResult?, Never>?
+
+    init(
+        captureContext: @escaping @Sendable ([String]) async -> String?,
+        dateProvider: @escaping @Sendable () -> Date = Date.init
+    ) {
+        self.captureContext = captureContext
+        self.dateProvider = dateProvider
+    }
+
+    func start(customWords: [String]) {
+        let newTask = Task<ScreenContextPrefetchResult?, Never> { [captureContext, dateProvider] in
+            let startedAt = dateProvider()
+            let context = await captureContext(customWords)
+            guard !Task.isCancelled else {
+                return nil
+            }
+
+            return ScreenContextPrefetchResult(
+                context: context,
+                elapsed: dateProvider().timeIntervalSince(startedAt)
+            )
+        }
+
+        let previousTask = lock.withLock { () -> Task<ScreenContextPrefetchResult?, Never>? in
+            let previousTask = task
+            task = newTask
+            return previousTask
+        }
+        previousTask?.cancel()
+    }
+
+    func cancel() {
+        let previousTask = lock.withLock { () -> Task<ScreenContextPrefetchResult?, Never>? in
+            let previousTask = task
+            task = nil
+            return previousTask
+        }
+        previousTask?.cancel()
+    }
+
+    func resolve() async -> ScreenContextPrefetchResult? {
+        let currentTask = lock.withLock { () -> Task<ScreenContextPrefetchResult?, Never>? in
+            let currentTask = task
+            task = nil
+            return currentTask
+        }
+        guard let currentTask else {
+            return nil
+        }
+
+        return await currentTask.value
+    }
+}
