+struct LiveFrontmostWindowScreenshotCapturer: WindowScreenshotCapturing {
+    private let frontmostProcessIDProvider: @Sendable () async -> pid_t?
+    private let windowInfoProvider: @Sendable () -> [[String: Any]]
+    private let shareableContentProvider: @Sendable () async throws -> SCShareableContent
+    private let captureImageAction: @Sendable (SCContentFilter, SCStreamConfiguration) async throws -> CGImage
+
+    init(
+        frontmostProcessIDProvider: @escaping @Sendable () async -> pid_t? = {
+            await MainActor.run {
+                NSWorkspace.shared.frontmostApplication?.processIdentifier
+            }
+        },
+        windowInfoProvider: @escaping @Sendable () -> [[String: Any]] = {
+            CGWindowListCopyWindowInfo([.optionOnScreenOnly, .excludeDesktopElements], kCGNullWindowID) as? [[String: Any]] ?? []
+        },
+        shareableContentProvider: @escaping @Sendable () async throws -> SCShareableContent = {
+            try await SCShareableContent.current
+        },
+        captureImageAction: @escaping @Sendable (SCContentFilter, SCStreamConfiguration) async throws -> CGImage = { filter, configuration in
+            try await withCheckedThrowingContinuation { continuation in
+                SCScreenshotManager.captureImage(contentFilter: filter, configuration: configuration) { image, error in
+                    if let error {
+                        continuation.resume(throwing: error)
+                        return
+                    }
+                    guard let image else {
+                        continuation.resume(throwing: CocoaError(.fileReadUnknown))
+                        return
+                    }
+                    continuation.resume(returning: image)
+                }
+            }
+        }
+    ) {
+        self.frontmostProcessIDProvider = frontmostProcessIDProvider
+        self.windowInfoProvider = windowInfoProvider
+        self.shareableContentProvider = shareableContentProvider
+        self.captureImageAction = captureImageAction
+    }
+
+    func captureImage() async throws -> CGImage? {
+        guard let processID = await frontmostProcessIDProvider() else {
+            return nil
+        }
+
+        let windows = windowInfoProvider().compactMap(Self.candidate(from:))
+        guard let targetWindow = FrontmostWindowSelection.selectFrontmostWindow(for: processID, windows: windows) else {
+            return nil
+        }
+
+        let shareableContent = try await shareableContentProvider()
+        guard let shareableWindow = shareableContent.windows.first(where: { $0.windowID == targetWindow.windowID }) else {
+            return nil
+        }
+
+        let filter = SCContentFilter(desktopIndependentWindow: shareableWindow)
+        let configuration = SCStreamConfiguration()
+        configuration.width = max(Int(ceil(targetWindow.frame.width * 2.0)), 1)
+        configuration.height = max(Int(ceil(targetWindow.frame.height * 2.0)), 1)
+        configuration.scalesToFit = false
+        configuration.showsCursor = false
+        return try await captureImageAction(filter, configuration)
+    }
+
+    private static func candidate(from windowInfo: [String: Any]) -> FrontmostWindowCandidate? {
+        guard
+            let windowID = (windowInfo[kCGWindowNumber as String] as? NSNumber)?.uint32Value,
+            let ownerPID = (windowInfo[kCGWindowOwnerPID as String] as? NSNumber)?.int32Value,
+            let layer = (windowInfo[kCGWindowLayer as String] as? NSNumber)?.intValue,
+            let bounds = windowInfo[kCGWindowBounds as String] as? NSDictionary,
+            let frame = CGRect(dictionaryRepresentation: bounds)
+        else {
+            return nil
+        }
+
+        let alpha = (windowInfo[kCGWindowAlpha as String] as? NSNumber)?.doubleValue ?? 1.0
+        return FrontmostWindowCandidate(
+            windowID: windowID,
+            ownerPID: ownerPID,
+            layer: layer,
+            alpha: alpha,
+            frame: frame
+        )
+    }
+}
+
+struct LiveWindowTextRecognizer: WindowTextRecognizing {
+    func recognizeText(in image: CGImage, customWords: [String]) async throws -> RecognizedScreenText? {
+        let request = VNRecognizeTextRequest()
+        request.recognitionLevel = .accurate
+        request.usesLanguageCorrection = true
+        request.customWords = customWords
+        request.revision = VNRecognizeTextRequestRevision3
+
+        let handler = VNImageRequestHandler(cgImage: image)
+        try handler.perform([request])
+
+        let observations = (request.results ?? []).compactMap { observation -> ScreenTextObservation? in
+            guard let candidate = observation.topCandidates(1).first else {
+                return nil
+            }
+
+            return ScreenTextObservation(
+                text: candidate.string,
+                boundingBox: observation.boundingBox,
+                confidence: Double(candidate.confidence)
+            )
+        }
+
+        return RecognizedScreenText.fromObservations(observations)
+    }
+}
+
+enum ScreenContextLogger {
+    static let liveDiagnostic: @Sendable (String) -> Void = { message in
+        print("[OCR] \(message)")
+    }
+
+    static let liveSensitive: @Sendable (String) -> Void = { message in
+        print("[OCR Sensitive] \(message)")
+    }
+}
